          // Functions assigned in inner scopes are inferred.
          AstFunctionContents contents =
              getFunctionAnalysisResults(scope.getRootNode());
          if (contents != null &&
              contents.getEscapedQualifiedNames().contains(qName)) {
            return false;
          }
          return true;
        }
      }
